components.codeTemplate:
@Namespace private var namespace

GlassEffectContainer {
    Image(systemName: "plus")
        .padding()
        .glassEffect()
        .glassEffectID({id}, in: {namespace})
}

@Namespace private var namespace

GlassEffectContainer {
    HStack {
        ForEach(items) { item in
            Image(systemName: item.icon)
                .padding()
                .glassEffect()
                .glassEffectUnion(id: {id}, namespace: {namespace})
        }
    }
}

.toolbar {
    ToolbarItem(placement: .{placement}) {
        Button("Edit") { }
    }
    ToolbarSpacer(.{sizing}, placement: .{placement})
    ToolbarItem(placement: .{placement}) {
        Button("Done") { }
    }
}

Image(systemName: "heart.fill")
    .phaseAnimator({phases}, trigger: {trigger}) { content, phase in
        content.scaleEffect(phase)
    } animation: { _ in
        .{animation}
    }

Image(systemName: "star.fill")
    .keyframeAnimator(initialValue: AnimationValues(), trigger: {trigger}) { content, value in
        content
            .scaleEffect(value.scale)
            .rotationEffect(value.rotation)
    } keyframes: { _ in
        KeyframeTrack(\.scale) {
            {keyframeType}(1.2, duration: {duration})
            {keyframeType}(1.0, duration: {duration})
        }
    }

if isShown {
    CardView()
        .transition(.{transition})
}
// trigger inside: withAnimation { isShown.toggle() }

@Namespace private var namespace

image
    .matchedGeometryEffect(id: {id}, in: {namespace}, properties: .{properties}, anchor: .{anchor}, isSource: {isSource})

struct TwirlTransition: Transition {
    func body(content: Content, phase: TransitionPhase) -> some View {
        content
            .rotationEffect(.degrees(phase.isIdentity ? 0 : {rotationDegrees}))
            .scaleEffect(phase.isIdentity ? 1 : {scaleAmount})
            .opacity(phase.isIdentity ? 1 : 0)
    }
}

// usage:
view.transition(TwirlTransition().animation(.{animation}))

image
    .colorEffect(
        ShaderLibrary.default.myColorShader(.float({uniform})),
        isEnabled: {isEnabled}
    )
// layerEffect / distortionEffect also take maxSampleOffset: CGSize(width: {maxSampleOffset}, height: {maxSampleOffset})

ScrollView {
    LazyVStack { /* rows */ }
}
.safeAreaBar(edge: .{edge}, alignment: .{alignment}, spacing: {spacing}) {
    Button("Action") { }
        .buttonStyle(.glassProminent)
}
